module top_module(obf_a, b, op, result);input signed [12:0] obf_a, b;
  input [4:0] op;
  output reg signed [12:0] result; // Change output to reg

  always @(*) begin
    case (op)
      5'b00000: result = obf_a + b;
      5'b00001: result = obf_a - b;
      5'b00010: result = obf_a & b;
      5'b00011: result = obf_a | b;
      5'b00100: result = obf_a ^ b;
      5'b00101: result = (b[2:0] > 0) ? (obf_a << b[2:0]) : obf_a;
      5'b00110: result = (b[2:0] > 0) ? (obf_a >> b[2:0]) : obf_a;
      default: result = 0;
    endcase
  end
endmodule
